@techreport{lovelace_cycle_2023,
  type = {Research {{Excellence Framework}}},
  title = {Cycle Network Policy, Planning and Investment Transformed by the {{Propensity}} to {{Cycle Tool}}},
  author = {Lovelace, Robin and Birkin, M and Talbot, Joseph and Morgan, Malcolm},
  year = {2023},
  institution = {{University of Leeds}},
  abstract = {The Propensity to Cycle Tool (PCT) has revolutionised strategic cycle planning in England and Wales. This evidence-based tool quantifies cycling potential at national, city and street scales, leading to the creation of joined-up networks available to millions of people. The PCT has been used by {$&gt;$}35,000 transport planners, consultants, advocates and members of the public, directly influencing the design and construction of cost-effective cycle networks worth {$&gt;$}GBP500,000,000. The tool informed the majority of UK local authority applications to the GBP250,000,000 government COVID-19 Emergency Active Travel Fund. Planners across Europe, USA, Australia and New Zealand have adopted the approach internationally.},
  copyright = {CC0 1.0 Universal Public Domain Dedication}
}

